#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, M; scanf("%lld %lld", &N, &M);
        long long maxRuns = M * 36LL;
        if(N <= maxRuns) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

